//! Simple benchmark comparing stats-rs OLS performance to R

use stats_models::Lm;
use std::fs::File;
use std::io::Write;
use std::process::Command;
use std::time::Instant;

fn main() -> Result<(), Box<dyn std::error::Error>> {
    println!("=== stats-rs vs R Performance Comparison ===");

    // Test with mtcars-like dataset (32 obs, 2 predictors + intercept)
    let n_obs = 32;
    let n_vars = 3; // intercept + 2 predictors

    // Generate realistic automotive data similar to mtcars
    let mut x_data = Vec::with_capacity(n_obs * n_vars);
    let mut y_data = Vec::with_capacity(n_obs);

    // Predictors: weight (wt) and horsepower (hp)
    let weights = vec![
        2.620, 2.875, 2.320, 3.215, 3.440, 3.460, 3.570, 3.190, 3.150, 3.440, 3.440, 4.070, 3.730,
        3.780, 5.250, 5.424, 5.345, 2.200, 1.615, 1.835, 2.465, 3.520, 3.435, 3.840, 3.845, 1.935,
        2.140, 1.513, 2.780, 3.217, 2.770, 3.570,
    ];
    let horsepowers = vec![
        110.0, 110.0, 93.0, 110.0, 175.0, 105.0, 245.0, 62.0, 95.0, 123.0, 123.0, 180.0, 180.0,
        180.0, 205.0, 215.0, 230.0, 66.0, 52.0, 65.0, 97.0, 150.0, 150.0, 245.0, 175.0, 66.0, 91.0,
        113.0, 264.0, 175.0, 335.0, 109.0,
    ];

    // Response: mpg (miles per gallon) - roughly mpg = 37 - 3.2*wt - 0.03*hp + noise
    for i in 0..n_obs {
        x_data.push(1.0); // intercept
        x_data.push(weights[i]);
        x_data.push(horsepowers[i]);

        let mpg = 37.0 - 3.2 * weights[i] - 0.03 * horsepowers[i] + (i as f64 * 0.1 - 1.6); // some noise
        y_data.push(mpg);
    }

    // Create CSV file for R
    let csv_file = "/tmp/bench_data.csv";
    {
        let mut file = File::create(csv_file)?;
        writeln!(file, "mpg,wt,hp")?;
        for i in 0..n_obs {
            writeln!(file, "{},{},{}", y_data[i], weights[i], horsepowers[i])?;
        }
    }

    // Benchmark Rust implementation (multiple runs for stable timing)
    println!("Benchmarking Rust implementation...");
    let mut rust_times = Vec::new();
    for _ in 0..100 {
        let start = Instant::now();
        let _fit = Lm::fit(&x_data, &y_data, n_obs, n_vars)?;
        rust_times.push(start.elapsed().as_nanos() as f64);
    }

    let rust_mean = rust_times.iter().sum::<f64>() / rust_times.len() as f64;
    rust_times.sort_by(|a, b| a.partial_cmp(b).unwrap());
    let rust_median = rust_times[rust_times.len() / 2];

    println!("Rust timing (100 runs):");
    println!(
        "  Mean:   {:.0} ns ({:.3} ms)",
        rust_mean,
        rust_mean / 1_000_000.0
    );
    println!(
        "  Median: {:.0} ns ({:.3} ms)",
        rust_median,
        rust_median / 1_000_000.0
    );

    // Benchmark R implementation
    println!("\nBenchmarking R implementation...");
    let r_script = format!(
        r#"
        data <- read.csv("{}")
        times <- numeric(100)
        for(i in 1:100) {{
            start_time <- Sys.time()
            fit <- lm(mpg ~ wt + hp, data = data)
            end_time <- Sys.time()
            times[i] <- as.numeric(end_time - start_time, units = "secs") * 1e9  # convert to nanoseconds
        }}
        cat(sprintf("R Mean: %.0f ns\n", mean(times)))
        cat(sprintf("R Median: %.0f ns\n", median(times)))
        cat(sprintf("R Min: %.0f ns\n", min(times)))
    "#,
        csv_file
    );

    let output = Command::new("Rscript").arg("-e").arg(&r_script).output()?;

    if !output.status.success() {
        eprintln!(
            "R benchmark failed: {}",
            String::from_utf8_lossy(&output.stderr)
        );
        return Err("R benchmark failed".into());
    }

    let r_output = String::from_utf8_lossy(&output.stdout);
    println!("{}", r_output);

    // Parse R results and calculate speedup
    let r_lines: Vec<&str> = r_output.lines().collect();
    if let Some(mean_line) = r_lines.iter().find(|line| line.starts_with("R Mean:")) {
        if let Some(median_line) = r_lines.iter().find(|line| line.starts_with("R Median:")) {
            let r_mean: f64 = mean_line
                .split_whitespace()
                .nth(2)
                .unwrap_or("0")
                .replace(",", "")
                .parse()
                .unwrap_or(0.0);
            let r_median: f64 = median_line
                .split_whitespace()
                .nth(2)
                .unwrap_or("0")
                .replace(",", "")
                .parse()
                .unwrap_or(0.0);

            println!("\n=== PERFORMANCE COMPARISON ===");
            println!("Rust mean:   {:.3} ms", rust_mean / 1_000_000.0);
            println!("R mean:      {:.3} ms", r_mean / 1_000_000.0);
            println!("Speedup:     {:.2}x", r_mean / rust_mean);
            println!();
            println!("Rust median: {:.3} ms", rust_median / 1_000_000.0);
            println!("R median:    {:.3} ms", r_median / 1_000_000.0);
            println!("Speedup:     {:.2}x", r_median / rust_median);

            let target_speedup = 2.0;
            let actual_speedup = r_median / rust_median;

            println!("\n=== TARGET ASSESSMENT ===");
            if actual_speedup >= target_speedup {
                println!(
                    "✅ SUCCESS: Achieved {:.2}x speedup (target: {:.1}x)",
                    actual_speedup, target_speedup
                );
            } else {
                println!(
                    "❌ BELOW TARGET: {:.2}x speedup (target: {:.1}x)",
                    actual_speedup, target_speedup
                );
                println!(
                    "   Need {:.2}x improvement to reach target",
                    target_speedup / actual_speedup
                );
            }
        }
    }

    // Clean up
    std::fs::remove_file(csv_file).ok();

    Ok(())
}

